# Security configuration
RATE_LIMIT_WINDOW = 60  # seconds
RATE_LIMIT_MAX_REQUESTS = 100
MAX_REQUEST_SIZE = 1048576  # 1MB
ALLOWED_METHODS = ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS']

# In-memory rate limiting (use Redis/Cosmos DB for production)
rate_limit_store = {}

def clean_rate_limit_store():
    """Remove expired entries from rate limit store"""
    current_time = time.time()
    expired_keys = [k for k, v in rate_limit_store.items() 
                    if current_time - v['start_time'] > RATE_LIMIT_WINDOW]
    for key in expired_keys:
        del rate_limit_store[key]

def check_rate_limit(client_id: str) -> tuple[bool, int]:
    """Check if client has exceeded rate limit"""
    clean_rate_limit_store()
    current_time = time.time()
    
    if client_id not in rate_limit_store:
        rate_limit_store[client_id] = {
            'count': 1,
            'start_time': current_time
        }
        return True, RATE_LIMIT_MAX_REQUESTS - 1
    
    client_data = rate_limit_store[client_id]
    
    if current_time - client_data['start_time'] > RATE_LIMIT_WINDOW:
        rate_limit_store[client_id] = {
            'count': 1,
            'start_time': current_time
        }
        return True, RATE_LIMIT_MAX_REQUESTS - 1
    
    if client_data['count'] >= RATE_LIMIT_MAX_REQUESTS:
        return False, 0
    
    client_data['count'] += 1
    return True, RATE_LIMIT_MAX_REQUESTS - client_data['count']

def get_client_identifier(req: func.HttpRequest) -> str:
    """Get unique client identifier for rate limiting"""
    forwarded_for = req.headers.get('X-Forwarded-For', '')
    if forwarded_for:
        client_ip = forwarded_for.split(',')[0].strip()
    else:
        client_ip = req.headers.get('X-Real-IP', 'unknown')
    
    user_agent = req.headers.get('User-Agent', '')
    identifier = f"{client_ip}:{user_agent}"
    return hashlib.sha256(identifier.encode()).hexdigest()

def validate_request_size(req: func.HttpRequest) -> bool:
    """Validate request body size"""
    try:
        content_length = int(req.headers.get('Content-Length', 0))
        return content_length <= MAX_REQUEST_SIZE
    except (ValueError, TypeError):
        return True

def sanitize_input(data: str) -> str:
    """Basic input sanitization"""
    if not data:
        return data
    
    dangerous_chars = ['<', '>', '"', "'", '&', ';', '(', ')', '{', '}']
    sanitized = data
    for char in dangerous_chars:
        sanitized = sanitized.replace(char, '')
    
    return sanitized[:1000]  # Limit length

def create_cors_response(
    body: dict,
    status_code: int = 200,
    headers: Optional[dict] = None
) -> func.HttpResponse:
    """Create HTTP response with CORS headers"""
    response_headers = {
        'Access-Control-Allow-Origin': '*',
        'Access-Control-Allow-Methods': ', '.join(ALLOWED_METHODS),
        'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Requested-With, X-API-Key',
        'Access-Control-Max-Age': '3600',
        'Content-Type': 'application/json',
        'X-Content-Type-Options': 'nosniff',
        'X-Frame-Options': 'DENY',
        'X-XSS-Protection': '1; mode=block',
        'Strict-Transport-Security': 'max-age=31536000; includeSubDomains',
        'Content-Security-Policy': "default-src 'self'"
    }
    
    if headers:
        response_headers.update(headers)
    
    return func.HttpResponse(
        body=json.dumps(body),
        status_code=status_code,
        headers=response_headers,
        mimetype='application/json'
    )

def handle_preflight() -> func.HttpResponse:
    """Handle CORS preflight requests"""
    return func.HttpResponse(
        status_code=204,
        headers={
            'Access-Control-Allow-Origin': '*',
            'Access-Control-Allow-Methods': ', '.join(ALLOWED_METHODS),
            'Access-Control-Allow-Headers': 'Content-Type, Authorization, X-Requested-With, X-API-Key',
            'Access-Control-Max-Age': '3600'
        }
    )

